import React from 'react';

const RoleSelection = ({ onSelectRole }) => {
  return (
    <div className="login-container">
      <div className="role-selection-box">
        <h1>🏥 AI Healthcare</h1>
        <h2>Select Your Role</h2>
        <div className="role-cards">
          <div className="role-card" onClick={() => onSelectRole('patient')}>
            <div className="role-icon">🧑‍⚕️</div>
            <h3>Patient</h3>
            <p>Access your health records and chat with AI assistant</p>
          </div>
          <div className="role-card" onClick={() => onSelectRole('doctor')}>
            <div className="role-icon">👨‍⚕️</div>
            <h3>Doctor</h3>
            <p>Manage patients and review prescriptions</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RoleSelection;
